external_knowledge:
- 'life partnerships' refers to marital_status;
- 'professions' refer to occupation;
- 'financial skies' and 'golden clouds' metaphorically refer to income and wealth;
- 'economic sky' refers to the combined economic environment of marital status and occupation;
- 'categorized by zones of wealth' refers to the division of average incomes into quintiles (five groups).

sql:
SELECT AVG(salary) AS average_income
FROM demographics
WHERE marital_status = 'Married-civ-spouse' AND sex = 'Male';

SELECT AVG(age) AS average_age
FROM demographics
WHERE income_result = '>50K';

SELECT age, income_result
FROM demographics
ORDER BY age DESC;

SELECT AVG(salary) AS average_salary
FROM demographics
WHERE income_result = '>50K';

SELECT COUNT(DISTINCT o.occupation_name) AS high_education_occupations
FROM occupations o
WHERE o.required_education IN ('Bachelors', 'Masters', 'Doctorate');
